var inputItem = $input.first() || {};
var sourceJson = inputItem.json || {};
var sourceBinary = inputItem.binary || {};
var binaryKeys = Object.keys(sourceBinary);

// Find all PDF binary keys
var pdfKeys = [];
for (var index = 0; index < binaryKeys.length; index += 1) {
  var file = sourceBinary[binaryKeys[index]] || {};
  var fileName = String(file.fileName || '').toLowerCase();
  var mimeType = String(file.mimeType || '').toLowerCase();
  if (mimeType === 'application/pdf' || fileName.endsWith('.pdf')) {
    pdfKeys.push(binaryKeys[index]);
  }
}
if (pdfKeys.length === 0) {
  throw new Error('The form submission did not include any PDF files.');
}

var duplicateMode = String(
  sourceJson['Duplikatsmodus'] ||
  sourceJson['Duplicate Mode'] ||
  sourceJson.duplicate_mode ||
  'overwrite'
).toLowerCase();
if (['skip', 'overwrite'].indexOf(duplicateMode) === -1) {
  duplicateMode = 'overwrite';
}
var submittedAt = sourceJson.submittedAt || sourceJson.submitted_at || null;

// Emit one item per PDF
var results = [];
for (var pdfIdx = 0; pdfIdx < pdfKeys.length; pdfIdx += 1) {
  var pdfKey = pdfKeys[pdfIdx];
  results.push({
    json: {
      source_filename: sourceBinary[pdfKey].fileName || 'form-upload-' + (pdfIdx + 1) + '.pdf',
      ingestion_channel: 'form',
      received_date: submittedAt,
      duplicate_mode: duplicateMode,
      persist_result: true,
      persistence_mode: 'postgres'
    },
    binary: {
      pdf: sourceBinary[pdfKey]
    }
  });
}
return results;
